const settings = $('Load Global Settings').first()?.json ?? {};
const request = $('Send Refund Request Email Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? request.query ?? {};
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const truthy = (value) => ['1', 'true', 'yes', 'y', 'on'].includes(clean(value).toLowerCase());
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const refundId = Number.parseInt(clean(body.refund_id), 10);
const actionType = clean(body.action_type);
const renderedSubject = clean(body.rendered_subject);
const renderedMessage = clean(body.rendered_message);
const templateKey = clean(body.template_key);
const intendedRecipient = clean(body.intended_recipient);
const returnUrl = clean(body.return_url) || `${n8nBaseUrl}/webhook/refunds${Number.isInteger(refundId) ? `?id=${refundId}` : ''}`;
const deliveryMode = truthy(body.test_mode) ? 'test' : 'production';
const validActions = ['request_bank_details', 'submit_refund_request'];
const actionConfig = {
  request_bank_details: {
    successMessage: 'Bank details request sent',
    nextStatus: 'Request Bank Details',
    messageColumn: 'request_email_message_id',
    title: 'Bank Details Request Sent'
  },
  submit_refund_request: {
    successMessage: 'Refund request submitted to treasury',
    nextStatus: 'Submitted for Refund',
    messageColumn: 'treasury_email_message_id',
    title: 'Treasury Request Sent'
  }
};
const config = actionConfig[actionType] ?? null;
const errorMessage = !Number.isInteger(refundId)
  ? 'Refund id is required.'
  : !validActions.includes(actionType)
    ? 'Refund email action is not recognised.'
    : !templateKey
      ? 'Template key is required.'
      : !renderedSubject
        ? 'Email subject is required.'
        : !renderedMessage
          ? 'Email message is required.'
          : !intendedRecipient
            ? 'Recipient email is required.'
            : '';
return [{ json: {
  refund_id: refundId,
  action_type: actionType,
  template_key: templateKey,
  sender_name: settings.email_sender_name || 'Steve Short',
  reply_to: settings.email_reply_to || 'members.avondaleltc@gmail.com',
  delivery_mode: deliveryMode,
  test_recipient: clean(settings.default_test_recipient) || 'steve.short@gmail.com',
  return_url: returnUrl,
  rendered_subject: renderedSubject,
  rendered_message: renderedMessage,
  email_type: clean(body.email_type).toLowerCase() === 'html' ? 'html' : 'text',
  intended_recipient: intendedRecipient,
  actual_recipient: deliveryMode === 'production' ? intendedRecipient : (clean(settings.default_test_recipient) || 'steve.short@gmail.com'),
  success_message: config?.successMessage || 'Refund email sent',
  next_status: config?.nextStatus || '',
  message_column: config?.messageColumn || '',
  success_title: config?.title || 'Refund Email Sent',
  error_message: errorMessage
} }];

const input = $('Resolve Send Request').first().json ?? {};
const message = input.error_message || 'Unable to send refund email.';
const redirectTo = `${input.return_url || '#'}${(input.return_url || '').includes('?') ? '&' : '?'}error=${encodeURIComponent(message)}${input.refund_id ? `&id=${encodeURIComponent(input.refund_id)}` : ''}`;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=${escapeHtml(redirectTo)}"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Refund Email Not Sent</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Refund Email Not Sent</h1><p>${escapeHtml(message)}</p><p><a class="button" href="${escapeHtml(redirectTo)}">Back to refunds</a></p></div></body></html>`;
return [{ json: { html } }];

const input = $('Resolve Send Request').first().json ?? {};
const result = $('Send Gmail Message').first()?.json ?? {};
const messageId = result.id || result.message?.id || '';
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sqlParts = [
  `status = ${sqlLiteral(input.next_status)}`,
  `${input.message_column} = ${sqlLiteral(messageId)}`,
  'updated_at = now()'
];
if (input.next_status === 'Refund Processed') sqlParts.push('paid_at = now()');
if (input.next_status === 'Refund Rejected') sqlParts.push('rejected_at = now()');
const sql = `UPDATE public.refunds SET ${sqlParts.join(', ')} WHERE id = ${input.refund_id} RETURNING id, refund_for, status;`;
return [{ json: { ...input, message_id: messageId, sql } }];

const item = $('Build Update SQL').first().json ?? {};
const updated = $('Update Refund Status').first()?.json ?? {};
const modeLabel = item.delivery_mode === 'production' ? 'Production' : 'Test';
const recipientSummary = item.delivery_mode === 'production' ? item.actual_recipient : `${item.actual_recipient} (intended recipient: ${item.intended_recipient})`;
const redirectTo = `${item.return_url || '#'}${(item.return_url || '').includes('?') ? '&' : '?'}message=${encodeURIComponent(item.success_message)}&id=${encodeURIComponent(updated.id || item.refund_id)}`;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=${escapeHtml(redirectTo)}"><meta name="viewport" content="width=device-width, initial-scale=1"><title>${escapeHtml(item.success_title)}</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.pill{display:inline-flex;align-items:center;padding:8px 12px;border-radius:999px;background:#edf8f2;color:#1f7a4d;font-weight:700;margin:12px 0 18px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>${escapeHtml(item.success_title)}</h1><p>Returning to refunds…</p><div class="pill">${escapeHtml(modeLabel)} mode</div><p>Recipient: ${escapeHtml(recipientSummary)}</p><p><a class="button" href="${escapeHtml(redirectTo)}">Continue</a></p></div></body></html>`;
return [{ json: { html } }];
